parameters.jsCode:
let content = $json.text || $json.response?.text || $json.content || '{}';
content = String(content).trim();
content = content.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
const firstBrace = content.indexOf('{');
const lastBrace = content.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) { content = content.slice(firstBrace, lastBrace + 1); }
let ai = {};
try { ai = JSON.parse(content); } catch (e) { ai = {}; }
return { json: { ...$json, recommended_action: ai.recommended_action || 'Review', why_now: ai.why_now || '', draft_message: ai.draft_message || '', stage_bucket: ai.stage_bucket || 'New', urgency: ai.urgency || 'Medium' } };

const name = $json.lead_name || $json["Lead Name"] || $json.leadname || 'Unknown';

const line = `Who - ${name}\nAction - ${$json.recommended_action || ''}\nWhy - ${$json.why_now || ''}\n${$json.draft_message || ''}`;

return { json: { ...$json, digest_line: line } };

const items = $input.all();
const today = new Date().toISOString().split('T')[0];
const lines = items.map((item, i) => `${i + 1}. ${item.json.digest_line}`);
const body = lines.length
  ? `Daily outreach queue for ${today}\n\n${lines.join('\n\n')}`
  : `Daily outreach queue for ${today}\n\nNo leads due today.`;
return { json: { subject: `Daily Outreach Queue - ${today}`, body, due_count: items.length } };

const raw = $json["Next Action Date"];
let next_action_date_iso = '';
let due_today_or_earlier = false;

if (raw && String(raw).trim() !== '') {
  const s = String(raw).trim();

  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
    next_action_date_iso = s;
  } else {
    const d = new Date(s);
    if (!isNaN(d.getTime())) {
      next_action_date_iso = d.toISOString().split('T')[0];
    }
  }
}

const today = new Date().toISOString().split('T')[0];

if (next_action_date_iso && next_action_date_iso <= today) {
  due_today_or_earlier = true;
}

return {
  ...$json,
  next_action_date_iso,
  due_today_or_earlier
};

